#include <bits/stdc++.h>

using namespace std;

const long long NEG_INF = -250000000; // Define a very high negative number for unreachable points

// Function to check if the coordinates are within the grid bounds
bool isInBounds(int x, int y, int n) {
    return x >= 1 && x <= n && y >= 1 && y <= n;
}

// Recursive DP function with memoization
long long dp(int i, int j, int n, vector<vector<long long>>& memo, vector<vector<long long>>& A) {
    // Base cases
    if (!isInBounds(i, j, n)) return INT_MIN; // Out of bounds
    if (memo[i][j] != LLONG_MIN) return memo[i][j]; // Return already computed value
    if (i == n && j == n) return A[i][j]; // Reached bottom-right corner

    // Recursive calls to explore right and down movements
    memo[i][j] = A[i][j] + max(dp(i + 1, j, n, memo, A), dp(i, j + 1, n, memo, A));
    return memo[i][j];
}

int main() {
    int n, m; // Dimensions of the grid and number of reachable points
    cin >> n >> m;

    vector<vector<long long>> V(n + 1, vector<long long>(n + 1, 0)); // Original grid values
    vector<vector<long long>> A(n + 1, vector<long long>(n + 1, NEG_INF)); // Reachable grid values
    vector<vector<long long>> memo(n + 1, vector<long long>(n + 1, LLONG_MIN)); // Memoization table

    // Input the original grid values
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            cin >> V[i][j];
        }
    }

    // Input the reachable points and update the A grid
    while (m--) {
        int x, y, z;
        cin >> x >> y >> z; // Read reachable point coordinates and range
        for (int i = x - z; i <= x + z; i++) {
            if (i <= x) {
                for (int j = y - (i - x + z); j <= y + (i - x + z); j++) {
                    if (isInBounds(i, j, n)) {
                        A[i][j] = V[i][j]; // Assign values from original grid
                    }
                }
            } else {
                for (int j = y - (x - i + z); j <= y + (x - i + z); j++) {
                    if (isInBounds(i, j, n)) {
                        A[i][j] = V[i][j]; // Assign values from original grid
                    }
                }
            }
        }
    }

    // Compute maximum sum from top-left to bottom-right
    long long maxSum = dp(1, 1, n, memo, A);

    // Output the result
    if (maxSum < NEG_INF) {
        cout << "NO" << endl; // No path exists
    } else {
        cout << "YES" << endl; // Path exists
        cout << maxSum << endl; // Output maximum sum
    }

    return 0;
}

