import java.io.*;

class Codechef {

    // Define a very high negative number for unreachable points
    private static final long NEG_INF = -250000000;

    // Function to check if the coordinates are within the grid bounds
    private static boolean isInBounds(int x, int y, int n) {
        return x >= 1 && x <= n && y >= 1 && y <= n;
    }

    // Recursive DP function with memoization
    private static long dp(int i, int j, int n, long[][] memo, long[][] A) {
        // Base cases
        if (!isInBounds(i, j, n)) return Long.MIN_VALUE; // Out of bounds
        if (memo[i][j] != Long.MIN_VALUE) return memo[i][j]; // Return already computed value
        if (i == n && j == n) return A[i][j]; // Reached bottom-right corner

        // Recursive calls to explore right and down movements
        memo[i][j] = A[i][j] + Math.max(dp(i + 1, j, n, memo, A), dp(i, j + 1, n, memo, A));
        return memo[i][j];
    }

    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt(); // Dimensions of the grid
        int m = scanner.nextInt(); // Number of reachable points

        long[][] V = new long[n + 1][n + 1]; // Original grid values
        long[][] A = new long[n + 1][n + 1]; // Reachable grid values
        long[][] memo = new long[n + 1][n + 1]; // Memoization table

        // Initialize the memoization table with Long.MIN_VALUE
        for (int i = 0; i <= n; i++) {
            Arrays.fill(memo[i], Long.MIN_VALUE);
        }
        // Initialize the A grid with NEG_INF
        for (int i = 0; i <= n; i++) {
            Arrays.fill(A[i], NEG_INF);
        }

        // Input the original grid values
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                V[i][j] = scanner.nextLong();
            }
        }

        // Input the reachable points and update the A grid
        while (m-- > 0) {
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            int z = scanner.nextInt(); // Read reachable point coordinates and range
            for (int i = x - z; i <= x + z; i++) {
                if (i <= x) {
                    for (int j = y - (i - x + z); j <= y + (i - x + z); j++) {
                        if (isInBounds(i, j, n)) {
                            A[i][j] = V[i][j]; // Assign values from original grid
                        }
                    }
                } else {
                    for (int j = y - (x - i + z); j <= y + (x - i + z); j++) {
                        if (isInBounds(i, j, n)) {
                            A[i][j] = V[i][j]; // Assign values from original grid
                        }
                    }
                }
            }
