const NEG_INF = -250000000; // Define a very high negative number for unreachable points

// Function to check if the coordinates are within the grid bounds
function isInBounds(x, y, n) {
    return x >= 1 && x <= n && y >= 1 && y <= n;
}

// Recursive DP function with memoization
function dp(i, j, n, memo, A) {
    // Base cases
    if (!isInBounds(i, j, n)) return Number.MIN_SAFE_INTEGER; // Out of bounds
    if (memo[i][j] !== -Infinity) return memo[i][j]; // Return already computed value
    if (i === n && j === n) return A[i][j]; // Reached bottom-right corner

    // Recursive calls to explore right and down movements
    memo[i][j] = A[i][j] + Math.max(dp(i + 1, j, n, memo, A), dp(i, j + 1, n, memo, A));
    return memo[i][j];
}

function main() {
    const input = require('fs').readFileSync(0, 'utf-8').trim().split('\n'); // Read all input at once
    const firstLine = input[0].split(' ').map(Number);
    const n = firstLine[0];
    const m = firstLine[1];

    // Original grid values
    const V = Array.from({ length: n + 1 }, () => Array(n + 1).fill(0));
    const A = Array.from({ length: n + 1 }, () => Array(n + 1).fill(NEG_INF)); // Reachable grid values
    const memo = Array.from({ length: n + 1 }, () => Array(n + 1).fill(-Infinity)); // Memoization table

    // Input the original grid values
    for (let i = 1; i <= n; i++) {
        const row = input[i].split(' ').map(Number);
        for (let j = 1; j <= n; j++) {
            V[i][j] = row[j - 1];
        }
    }

    // Input the reachable points and update the A grid
    for (let k = 0; k < m; k++) {
        const [x, y, z] = input[n + 1 + k].split(' ').map(Number); // Read reachable point coordinates and range
        for (let i = x - z; i <= x + z; i++) {
            if (i <= x) {
                for (let j = y - (i - x + z); j <= y + (i - x + z); j++) {
                    if (isInBounds(i, j, n)) {
                        A[i][j] = V[i][j]; // Assign values from original grid
                    }
                }
            } else {
                for (let j = y - (x - i + z); j <= y + (x - i + z); j++) {
                    if (isInBounds(i, j, n)) {
                        A[i][j] = V[i][j]; // Assign values from original grid
                    }
                }
            }
        }
    }

    // Compute maximum sum from top-left to bottom-right
    const maxSum = dp(1, 1, n, memo, A);

    // Output the result
    if (maxSum < NEG_INF) {
        console.log("NO"); // No path exists
    } else {
        console.log("YES"); // Path exists
        console.log(maxSum); // Output maximum sum
    }
}

// Execute the main function
main();
